INSERT INTO public.products (name, slug, short_description, description, price, compare_at_price, stock, images, category_id, is_published, is_featured) VALUES
('SkyGear Pro X1', 'skygear-pro-x1', '4K HDR camera drone with 46-min flight time', 'The Pro X1 is our flagship aerial platform. A 1-inch CMOS sensor captures 5.4K/60 video, obstacle sensing in all directions keeps you safe, and OcuSync 4 delivers a 15 km transmission range.', 1299.00, 1499.00, 12, ARRAY['/__l5e/assets-v1/72813207-f894-4842-8792-83c55ac2695e/drone-pro-x1.jpg'], (SELECT id FROM c WHERE slug='drones'), true, true),
('SkyGear Mini Fold', 'skygear-mini-fold', 'Sub-250g foldable travel drone, 4K/30', 'Weighing less than 249 g, the Mini Fold slips into a jacket pocket yet shoots stabilized 4K/30 footage with a 3-axis gimbal. Perfect for travel creators.', 549.00, NULL, 30, ARRAY['/__l5e/assets-v1/8e99fa67-888a-4d2b-b783-a61017c93ae7/drone-mini.jpg'], (SELECT id FROM c WHERE slug='drones'), true, true),
('SkyGear FPV Racer', 'skygear-fpv-racer', 'Carbon-frame FPV drone, 140 km/h top speed', 'Purpose-built for freestyle and racing pilots. Carbon fiber frame, brushless 2306 motors, and analog/digital HD video options for a low-latency FPV experience.', 799.00, 899.00, 8, ARRAY['/__l5e/assets-v1/6c608387-9f92-4d01-99ca-17fe6ae3b9f1/drone-fpv.jpg'], (SELECT id FROM c WHERE slug='drones'), true, true),
('SkyGear Cinema 8K', 'skygear-cinema-8k', 'Full-frame cinema drone with ProRes RAW', 'Built for professional cinematographers: dual-battery redundancy, full-frame 8K sensor, ProRes RAW, and a 55-minute flight time.', 4499.00, NULL, 4, ARRAY['/__l5e/assets-v1/1c46653e-5299-4427-b495-c3c3ddc73668/drone-cinema.jpg'], (SELECT id FROM c WHERE slug='drones'), true, true),
('Intelligent Flight Battery', 'intelligent-flight-battery', 'Swap batteries in under 30 seconds', '5000 mAh LiPo pack tuned for the Pro X1. Delivers up to 46 minutes of flight and includes onboard cell balancing and low-temp performance.', 189.00, NULL, 40, ARRAY['/__l5e/assets-v1/f861c289-724f-4af9-ae3f-9c221d9eab3e/battery.jpg'], (SELECT id FROM c WHERE slug='batteries'), true, false),
('Low-Noise Propellers (4-pack)', 'low-noise-propellers', 'Quieter flight, longer endurance', 'CNC-balanced propellers reduce sound signature by up to 4 dB while extending flight time by up to 5%.', 24.00, NULL, 120, ARRAY['/__l5e/assets-v1/3bcb351f-0e67-4612-bb8e-053502638bed/propellers.jpg'], (SELECT id FROM c WHERE slug='accessories'), true, false),
('3-Axis Handheld Gimbal', 'handheld-gimbal', 'Rock-steady footage from any camera', 'Repurpose your drone camera or mirrorless body with our brushless 3-axis stabilizer. 12-hour battery, ARRI-style side handle.', 349.00, 399.00, 15, ARRAY['/__l5e/assets-v1/e6386fc3-bd02-40ff-839a-41bdadadd61b/gimbal.jpg'], (SELECT id FROM c WHERE slug='gimbals'), true, true),
('Smart Controller with 7" Display', 'smart-controller', '1000-nit sunlight-readable screen', 'No more phone mounting. Built-in 1000-nit display, HDMI out, and a customizable HD downlink up to 15 km.', 729.00, NULL, 10, ARRAY['/__l5e/assets-v1/11ccce26-bb65-4738-9b97-32a3ec826232/controller.jpg'], (SELECT id FROM c WHERE slug='accessories'), true, false),
('Hardshell Travel Case', 'hardshell-case', 'IP67 waterproof, TSA carry-on friendly', 'Custom-cut foam holds one drone, six batteries, controller, and cables. Airline carry-on compliant.', 129.00, NULL, 25, ARRAY['/__l5e/assets-v1/dd5ed572-2d1a-4e18-9e74-b56e7dab9b41/case.jpg'], (SELECT id FROM c WHERE slug='accessories'), true, false),
('ND Filter Set (6-pack)', 'nd-filter-set', 'ND4/8/16/32/64/PL for perfect exposure', 'Multi-coated Schott glass filters that thread onto your drone gimbal camera. Includes travel case.', 89.00, 109.00, 60, ARRAY['/__l5e/assets-v1/6965b3bb-97ac-4700-8d84-da2099239d1a/filters.jpg'], (SELECT id FROM c WHERE slug='accessories'), true, false)
